WITH UnionData AS ( -- 전월 기말 (EOH) SELECT FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') AS YYYYMM, SEL_CODE, SITE, 구분, 구분_ORD, 도우코드, --MODEL_N_TYPE, [도우모델], 작업구분, ORG작업구분, [model], [Inch], DW_SITE, 0 AS BOH_MONTH, ISNULL(EOH_MONTH, 0) AS EOH_MONTH FROM V_DOI_PROD_SUBUL WHERE FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') =
#{yyyymm}
FORMAT(GETDATE(), 'yyyyMM')
AND SITE = #{site}
AND [도우모델] LIKE '%' + #{dwModel} + '%'
UNION ALL
-- 당월 기초 (BOH) SELECT YYYYMM, SEL_CODE, SITE, 구분, 구분_ORD, 도우코드, --MODEL_N_TYPE, [도우모델], 작업구분, ORG작업구분, [model], [Inch], DW_SITE, ISNULL(BOH_MONTH, 0) AS BOH_MONTH, 0 AS EOH_MONTH FROM V_DOI_PROD_SUBUL WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND [도우모델] LIKE '%' + #{dwModel} + '%'
) SELECT YYYYMM, SEL_CODE, SITE, 구분, 구분_ORD, 도우코드, --MODEL_N_TYPE, [도우모델], 작업구분, ORG작업구분, [model], [Inch], DW_SITE, SUM(BOH_MONTH) AS BOH_MONTH, SUM(EOH_MONTH) AS PREV_EOH_MONTH, SUM(BOH_MONTH) - SUM(EOH_MONTH) AS 차이수량, CASE WHEN SUM(EOH_MONTH) = 0 THEN '전월 데이터 없음' WHEN ABS(SUM(BOH_MONTH) - SUM(EOH_MONTH)) > 0.01 THEN '불일치' ELSE '정상' END AS 상태 FROM UnionData GROUP BY YYYYMM, SEL_CODE, SITE, 구분, 구분_ORD, 도우코드, [도우모델], 작업구분, ORG작업구분, [model], [Inch], DW_SITE ORDER BY [도우모델], YYYYMM

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN ABS((ISNULL(BOH_MONTH, 0) + ISNULL(IN_MONTH, 0) /*+ ISNULL(BONUS_MONTH, 0)*/) - (ISNULL(EOH_MONTH, 0) + ISNULL(OUT_MONTH, 0) + ISNULL(LOSS_MONTH, 0))) <= 0.01 --AND ABS(ISNULL(LOSS_MONTH, 0) - (ISNULL(NG_MONTH, 0) + ISNULL(수율제외_MONTH, 0) + ISNULL(REWORK진행_MONTH, 0))) <= 0.01 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN ABS((ISNULL(BOH_MONTH, 0) + ISNULL(IN_MONTH, 0) /*+ ISNULL(BONUS_MONTH, 0)*/) - (ISNULL(EOH_MONTH, 0) + ISNULL(OUT_MONTH, 0) + ISNULL(LOSS_MONTH, 0))) > 0.01 --OR ABS(ISNULL(LOSS_MONTH, 0) - (ISNULL(NG_MONTH, 0) + ISNULL(수율제외_MONTH, 0) + ISNULL(REWORK진행_MONTH, 0))) > 0.01 THEN 1 ELSE 0 END) AS ERROR_COUNT, 0 AS WARNING_COUNT FROM V_DOI_PROD_SUBUL WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}

WITH UnionData AS ( -- 전월 기말 (EOH) SELECT FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') AS YYYYMM, SITE, 구분, [도우모델], 0 AS BOH_MONTH, ISNULL(EOH_MONTH, 0) AS EOH_MONTH FROM V_DOI_PROD_SUBUL WHERE FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') =
#{yyyymm}
FORMAT(GETDATE(), 'yyyyMM')
AND SITE = #{site}
AND [도우모델] LIKE '%' + #{dwModel} + '%'
UNION ALL
-- 당월 기초 (BOH) SELECT YYYYMM, SITE, 구분, [도우모델], ISNULL(BOH_MONTH, 0) AS BOH_MONTH, 0 AS EOH_MONTH FROM V_DOI_PROD_SUBUL WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND [도우모델] LIKE '%' + #{dwModel} + '%'
), ContinuityData AS ( SELECT YYYYMM, SUM(BOH_MONTH) AS BOH_MONTH, SUM(EOH_MONTH) AS PREV_EOH_MONTH, CASE WHEN SUM(EOH_MONTH) = 0 THEN '전월 데이터 없음' WHEN ABS(SUM(BOH_MONTH) - SUM(EOH_MONTH)) > 0.01 THEN '불일치' ELSE '정상' END AS 상태 FROM UnionData GROUP BY YYYYMM, SITE, 구분, [도우모델] ) SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN 상태 = '정상' THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN 상태 = '불일치' THEN 1 ELSE 0 END) AS MISMATCH_COUNT, SUM(CASE WHEN 상태 = '전월 데이터 없음' THEN 1 ELSE 0 END) AS NO_DATA_COUNT FROM ContinuityData

WITH UnionData AS ( -- 전월 기말 (EOH) SELECT FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') AS YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK, 0 AS BOH, ISNULL(EOH, 0) AS EOH FROM DOI_STOCK WHERE FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') =
#{yyyymm}
FORMAT(GETDATE(), 'yyyyMM')
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
UNION ALL
-- 당월 기초 (BOH) SELECT YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK, ISNULL(BOH, 0) AS BOH, 0 AS EOH FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
) SELECT YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK, SUM(BOH) AS BOH, SUM(EOH) AS PREV_EOH, SUM(BOH) - SUM(EOH) AS 차이수량, CASE WHEN SUM(EOH) = 0 THEN '전월 데이터 없음' WHEN ABS(SUM(BOH) - SUM(EOH)) > 0.01 THEN '불일치' ELSE '정상' END AS 상태 FROM UnionData GROUP BY YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, STOCK ORDER BY MODEL, YYYYMM

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN ABS((ISNULL(BOH, 0) + ISNULL([INPUT], 0)) - (ISNULL([OUT], 0) + ISNULL(EOH, 0))) <= 0.01 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN ABS((ISNULL(BOH, 0) + ISNULL([INPUT], 0)) - (ISNULL([OUT], 0) + ISNULL(EOH, 0))) > 0.01 THEN 1 ELSE 0 END) AS ERROR_COUNT, 0 AS WARNING_COUNT FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}

WITH UnionData AS ( -- 전월 기말 (EOH) SELECT FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') AS YYYYMM, SITE, MODEL, MODEL_TYPE, STOCK, 0 AS BOH, ISNULL(EOH, 0) AS EOH FROM DOI_STOCK WHERE FORMAT(DATEADD(MONTH, 1, CAST(YYYYMM + '01' AS DATE)), 'yyyyMM') =
#{yyyymm}
FORMAT(GETDATE(), 'yyyyMM')
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
UNION ALL
-- 당월 기초 (BOH) SELECT YYYYMM, SITE, MODEL, MODEL_TYPE, STOCK, ISNULL(BOH, 0) AS BOH, 0 AS EOH FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
), ContinuityData AS ( SELECT YYYYMM, SUM(BOH) AS BOH, SUM(EOH) AS PREV_EOH, CASE WHEN SUM(EOH) = 0 THEN '전월 데이터 없음' WHEN ABS(SUM(BOH) - SUM(EOH)) > 0.01 THEN '불일치' ELSE '정상' END AS 상태 FROM UnionData GROUP BY YYYYMM, SITE, MODEL, MODEL_TYPE, STOCK ) SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN 상태 = '정상' THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN 상태 = '불일치' THEN 1 ELSE 0 END) AS MISMATCH_COUNT, SUM(CASE WHEN 상태 = '전월 데이터 없음' THEN 1 ELSE 0 END) AS NO_DATA_COUNT FROM ContinuityData

SELECT COALESCE(P.YYYYMM, S.YYYYMM) AS YYYYMM, COALESCE(P.SEL_CODE, S.SEL_CODE) AS SEL_CODE, COALESCE(P.SITE, S.SITE) AS SITE, COALESCE(P.MODEL, S.MODEL) AS MODEL, COALESCE(P.MODEL_TYPE, S.MODEL_TYPE) AS MODEL_TYPE, ISNULL(P.OUT_QTY, 0) AS PROD_OUT, ISNULL(S.INPUT_PROD, 0) AS STOCK_INPUT, ISNULL(P.OUT_QTY, 0) - ISNULL(S.INPUT_PROD, 0) AS DIFF_QTY, CASE WHEN ISNULL(P.OUT_QTY, 0) - ISNULL(S.INPUT_PROD, 0) = 0 THEN '일치' WHEN P.OUT_QTY IS NULL THEN '생산 데이터 없음' WHEN S.INPUT_PROD IS NULL THEN '입고 데이터 없음' ELSE '불일치' END AS STATUS, CASE WHEN ISNULL(P.OUT_QTY, 0) - ISNULL(S.INPUT_PROD, 0) != 0 THEN '생산OUT(' + CAST(ISNULL(P.OUT_QTY, 0) AS VARCHAR) + ') != 입고INPUT(' + CAST(ISNULL(S.INPUT_PROD, 0) AS VARCHAR) + ')' ELSE '' END AS REMARK FROM ( -- 생산 데이터 (OUT_MONTH 합계) SELECT YYYYMM, SEL_CODE, SITE, 도우모델 AS MODEL, 도우코드 AS MODEL_TYPE, SUM(OUT_MONTH) AS OUT_QTY FROM V_DOI_PROD_SUBUL
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND 도우모델 LIKE '%' + #{model} + '%'
GROUP BY YYYYMM, SEL_CODE, SITE, 도우모델, 도우코드 ) P FULL OUTER JOIN ( -- 입고 데이터 (INPUT 합계) SELECT YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, SUM([INPUT]) AS INPUT_PROD FROM DOI_STOCK
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
GROUP BY YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE ) S ON P.YYYYMM = S.YYYYMM AND P.SEL_CODE = S.SEL_CODE AND P.SITE = S.SITE AND P.MODEL = S.MODEL AND P.MODEL_TYPE = S.MODEL_TYPE ORDER BY YYYYMM DESC, SEL_CODE, SITE, MODEL, MODEL_TYPE

SELECT COALESCE(S.YYYYMM, SL.YYYYMM) AS YYYYMM, COALESCE(S.SEL_CODE, SL.SEL_CODE) AS SEL_CODE, COALESCE(S.SITE, SL.SITE) AS SITE, COALESCE(S.MODEL, SL.품번) AS MODEL, S.MODEL_TYPE, ISNULL(S.OUT_INVOICE, 0) AS STOCK_OUT, ISNULL(SL.판매수량, 0) AS SALE_QTY, ISNULL(S.OUT_INVOICE, 0) - ISNULL(SL.판매수량, 0) AS DIFF_QTY, CASE WHEN ISNULL(S.OUT_INVOICE, 0) - ISNULL(SL.판매수량, 0) = 0 THEN '일치' WHEN S.OUT_INVOICE IS NULL THEN '입고 데이터 없음' WHEN SL.판매수량 IS NULL THEN '판매 데이터 없음' ELSE '불일치' END AS STATUS, CASE WHEN ISNULL(S.OUT_INVOICE, 0) - ISNULL(SL.판매수량, 0) != 0 THEN '입고출고(' + CAST(ISNULL(S.OUT_INVOICE, 0) AS VARCHAR) + ') != 판매수량(' + CAST(ISNULL(SL.판매수량, 0) AS VARCHAR) + ')' ELSE '' END AS REMARK FROM ( -- 입고 데이터 (OUT 합계 = 판매출고) SELECT YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, SUM([OUT]) AS OUT_INVOICE FROM DOI_STOCK
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
GROUP BY YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE ) S FULL OUTER JOIN ( -- 판매 데이터 SELECT YYYYMM, SEL_CODE, SITE, 품번, SUM(수량) AS 판매수량 FROM DOI_SALE_RESC
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND 품번 LIKE '%' + #{model} + '%'
GROUP BY YYYYMM, SEL_CODE, SITE, 품번 ) SL ON S.YYYYMM = SL.YYYYMM AND S.SEL_CODE = SL.SEL_CODE AND S.SITE = SL.SITE AND S.MODEL_TYPE = SL.품번 ORDER BY YYYYMM DESC, SEL_CODE, SITE, MODEL, MODEL_TYPE

WITH DATA_CHECK AS ( SELECT CASE WHEN ISNULL(P.OUT_QTY, 0) - ISNULL(S.INPUT_PROD, 0) = 0 THEN '일치' WHEN P.OUT_QTY IS NULL THEN '생산 데이터 없음' WHEN S.INPUT_PROD IS NULL THEN '입고 데이터 없음' ELSE '불일치' END AS STATUS FROM ( SELECT YYYYMM, SEL_CODE, SITE, 도우모델 AS MODEL, 도우코드 AS MODEL_TYPE, SUM(OUT_MONTH) AS OUT_QTY FROM V_DOI_PROD_SUBUL
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND 도우모델 LIKE '%' + #{model} + '%'
GROUP BY YYYYMM, SEL_CODE, SITE, 도우모델, 도우코드 ) P FULL OUTER JOIN ( SELECT YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, SUM([INPUT]) AS INPUT_PROD FROM DOI_STOCK
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
GROUP BY YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE ) S ON P.YYYYMM = S.YYYYMM AND P.SEL_CODE = S.SEL_CODE AND P.SITE = S.SITE AND P.MODEL = S.MODEL AND P.MODEL_TYPE = S.MODEL_TYPE ) SELECT COUNT(*) AS totalCount, SUM(CASE WHEN STATUS = '일치' THEN 1 ELSE 0 END) AS normalCount, SUM(CASE WHEN STATUS = '불일치' THEN 1 ELSE 0 END) AS mismatchCount, SUM(CASE WHEN STATUS IN ('생산 데이터 없음', '입고 데이터 없음') THEN 1 ELSE 0 END) AS noDataCount FROM DATA_CHECK

WITH DATA_CHECK AS ( SELECT CASE WHEN ISNULL(S.OUT_INVOICE, 0) - ISNULL(SL.판매수량, 0) = 0 THEN '일치' WHEN S.OUT_INVOICE IS NULL THEN '입고 데이터 없음' WHEN SL.판매수량 IS NULL THEN '판매 데이터 없음' ELSE '불일치' END AS STATUS FROM ( SELECT YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE, SUM([OUT]) AS OUT_INVOICE FROM DOI_STOCK
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
GROUP BY YYYYMM, SEL_CODE, SITE, MODEL, MODEL_TYPE ) S FULL OUTER JOIN ( SELECT YYYYMM, SEL_CODE, SITE, 품번, SUM(수량) AS 판매수량 FROM DOI_SALE_RESC
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND 품번 LIKE '%' + #{model} + '%'
GROUP BY YYYYMM, SEL_CODE, SITE, 품번 ) SL ON S.YYYYMM = SL.YYYYMM AND S.SEL_CODE = SL.SEL_CODE AND S.SITE = SL.SITE AND S.MODEL_TYPE = SL.품번 ) SELECT COUNT(*) AS totalCount, SUM(CASE WHEN STATUS = '일치' THEN 1 ELSE 0 END) AS normalCount, SUM(CASE WHEN STATUS = '불일치' THEN 1 ELSE 0 END) AS mismatchCount, SUM(CASE WHEN STATUS IN ('입고 데이터 없음', '판매 데이터 없음') THEN 1 ELSE 0 END) AS noDataCount FROM DATA_CHECK

SELECT TOP 100 MODEL, STOCK, BOH, [INPUT], [OUT], EOH, (BOH + [INPUT] - [OUT]) AS CALC_EOH, EOH - (BOH + [INPUT] - [OUT]) AS DIFF FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
ORDER BY ABS(EOH - (BOH + [INPUT] - [OUT])) DESC, MODEL, STOCK

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN ABS(EOH - (BOH + [INPUT] - [OUT])) <= 0.01 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN ABS(EOH - (BOH + [INPUT] - [OUT])) > 0.01 THEN 1 ELSE 0 END) AS ERROR_COUNT FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'

WITH FAB AS ( SELECT 구분,MODEL,expen_sel,expen_sel명,sum([out]) as FAB_OUT_AMT --select * FROM DOI_COST WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
group by 구분,MODEL,expen_sel,expen_sel명 having sum([out]) != 0 ), STOCK AS( select 구분,MODEL,expen_sel,expen_sel명,sum([in_amt]) as STOCK_IN_AMT from DOI_STCO WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
group by 구분,MODEL,expen_sel,expen_sel명 having sum([in_amt]) != 0 )SELECT a.구분 as gubun, a.MODEL, a.expen_sel, a.expen_sel명 as expen_sel_name, FAB_OUT_AMT, STOCK_IN_AMT, FAB_OUT_AMT - STOCK_IN_AMT as DIFF_AMT, CASE WHEN FAB_OUT_AMT IS NULL THEN 'FAB OUT 없음' WHEN STOCK_IN_AMT IS NULL THEN '창고 IN 없음' WHEN FAB_OUT_AMT - STOCK_IN_AMT != 0 THEN '금액 차이' ELSE '정상' END as error_Type FROM FAB A FULL JOIN STOCK B ON (A.구분 = b.구분 and a.model = b.model and a.expen_sel = b.expen_sel);

WITH FAB AS ( SELECT 구분,MODEL,expen_sel,expen_sel명,sum([out]) as FAB_OUT_AMT --select * FROM DOI_COST WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
group by 구분,MODEL,expen_sel,expen_sel명 having sum([out]) != 0 ), STOCK AS( select 구분,MODEL,expen_sel,expen_sel명,sum([in_amt]) as STOCK_IN_AMT from DOI_STCO WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
group by 구분,MODEL,expen_sel,expen_sel명 having sum([in_amt]) != 0 )SELECT count(*) as TOTAL_COUNT, sum(CASE WHEN FAB_OUT_AMT IS NULL or STOCK_IN_AMT IS NULL or FAB_OUT_AMT - STOCK_IN_AMT != 0 then 0 else 1 END) as NORMAL_COUNT, count(CASE WHEN FAB_OUT_AMT IS NULL or STOCK_IN_AMT IS NULL or FAB_OUT_AMT - STOCK_IN_AMT != 0 then 1 END) as ERROR_COUNT FROM FAB A FULL JOIN STOCK B ON (A.구분 = b.구분 and a.model = b.model and a.expen_sel = b.expen_sel);

SELECT TOP 100 MODEL, 구분 AS GUBUN, EXPEN_SEL, BOH_AMT, IN_AMT, EOH_AMT, OUT_AMT, (BOH_AMT + IN_AMT - EOH_AMT) AS CALC_OUT_AMT, OUT_AMT - (BOH_AMT + IN_AMT - EOH_AMT) AS DIFF FROM DOI_STCO WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
ORDER BY ABS(OUT_AMT - (BOH_AMT + IN_AMT - EOH_AMT)) DESC, MODEL, GUBUN, EXPEN_SEL

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN ABS(OUT_AMT - (BOH_AMT + IN_AMT - EOH_AMT)) <= 0.01 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN ABS(OUT_AMT - (BOH_AMT + IN_AMT - EOH_AMT)) > 0.01 THEN 1 ELSE 0 END) AS ERROR_COUNT FROM DOI_STCO WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'

SELECT TOP 100 MODEL, STOCK, BOH, EOH, CASE WHEN BOH < 0 AND EOH < 0 THEN '둘 다 음수' WHEN BOH < 0 THEN 'BOH 음수' WHEN EOH < 0 THEN 'EOH 음수' ELSE '정상' END AS ERROR_TYPE, CASE WHEN BOH < 0 AND EOH < 0 THEN '기초재고와 기말재고 모두 음수입니다.' WHEN BOH < 0 THEN '기초재고가 음수입니다.' WHEN EOH < 0 THEN '기말재고가 음수입니다.' ELSE '' END AS REMARK FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
AND (BOH < 0 OR EOH < 0) ORDER BY CASE WHEN BOH < 0 AND EOH < 0 THEN 1 WHEN BOH < 0 THEN 2 WHEN EOH < 0 THEN 3 ELSE 4 END, MODEL, STOCK

SELECT COUNT(*) AS TOTAL_COUNT, SUM(CASE WHEN BOH >= 0 AND EOH >= 0 THEN 1 ELSE 0 END) AS NORMAL_COUNT, SUM(CASE WHEN BOH < 0 OR EOH < 0 THEN 1 ELSE 0 END) AS ERROR_COUNT FROM DOI_STOCK WHERE 1=1
AND YYYYMM = #{yyyymm}
AND SITE = #{site}
AND MODEL LIKE '%' + #{model} + '%'
